import React, { useEffect, useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";

const ProductScreen = () => {
  const [products, setProducts] = useState([]);
  const navigate = useNavigate();
  const userInfo = JSON.parse(localStorage.getItem("userInfo"));

  useEffect(() => {
    const fetchProducts = async () => {
      const { data } = await axios.get("http://localhost:5000/api/products");
      setProducts(data);
    };
    fetchProducts();
  }, []);

  const addToCartHandler = async (productId) => {
    if (!userInfo) {
      alert("Please login");
      navigate("/");
      return;
    }

    await axios.post("http://localhost:5000/api/cart", {
      user: userInfo._id,
      product: productId,
      quantity: 1,
    });

    alert("Item Added To Cart");
  };

  return (
    <div style={{ padding: "20px", background: "#f4f6f9", minHeight: "100vh" }}>
      
      {/* Top Navigation */}
      <div
        style={{
          display: "flex",
          justifyContent: "space-between",
          alignItems: "center",
          marginBottom: "20px",
        }}
      >
        <h2>🛒 Products</h2>

        <div>
          <button onClick={() => navigate("/cart")} style={navBtnStyle}>
            View Cart
          </button>

          <button onClick={() => navigate("/orders")} style={navBtnStyle}>
            View Orders
          </button>

          <button
            onClick={() => {
              localStorage.removeItem("userInfo");
              navigate("/");
            }}
            style={{ ...navBtnStyle, background: "#dc3545" }}
          >
            Logout
          </button>
        </div>
      </div>

      {/* Product Grid */}
      <div
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(auto-fill, minmax(250px, 1fr))",
          gap: "20px",
        }}
      >
        {products.map((p) => (
          <div
            key={p._id}
            style={{
              background: "#fff",
              padding: "15px",
              borderRadius: "10px",
              boxShadow: "0 0 10px rgba(0,0,0,0.1)",
              textAlign: "center",
            }}
          >
            {/* ✅ IMAGE ADDED */}
            <img
          src={p.image}
          alt={p.name}
          style={{
          width: "100%",
          height: "180px",
          objectFit: "cover",
          borderRadius: "8px",
          marginBottom: "10px",
         }}
/>

            <h3>{p.name}</h3>
            <p><b>Brand:</b> {p.brand}</p>
            <p><b>Category:</b> {p.category}</p>
            <p><b>Description:</b> {p.description}</p>
            <p><b>Stock:</b> {p.countInStock}</p>
            <p style={{ fontWeight: "bold" }}>₹ {p.price}</p>

            <button
              onClick={() => addToCartHandler(p._id)}
              style={{
                padding: "10px",
                width: "100%",
                background: "#28a745",
                color: "#fff",
                border: "none",
                borderRadius: "5px",
                cursor: "pointer",
              }}
            >
              Add To Cart
            </button>
          </div>
        ))}
      </div>
    </div>
  );
};

const navBtnStyle = {
  padding: "8px 12px",
  marginLeft: "10px",
  background: "#007bff",
  color: "white",
  border: "none",
  borderRadius: "5px",
  cursor: "pointer",
};

export default ProductScreen;
